previewCss:
.darma-loader-darma-custom-729 {
  color: var(--loader-color, #f59e0b);
  --loader-secondary-color: #fde68a;
  --loader-bg: #ffffff;
width: 60px;
aspect-ratio: 4;
--c:currentColor 90%,#0000;
background:
radial-gradient(circle closest-side at left 6px top 50%,var(--c)),
radial-gradient(circle closest-side ,var(--c)),
radial-gradient(circle closest-side at right 6px top 50%,var(--c));
background-size: 100% 100%;
background-repeat: no-repeat;
animation: darma-loader-darma-custom-729-l4 1s infinite alternate;
}
@keyframes darma-loader-darma-custom-729-l4 {
to{width:25px;aspect-ratio: 1}
}

